#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

__kernel void lud_diagonal(__global float *m,
                           __local float *shadow,
                           int matrix_dim,
                           int offset)
{
    const int tx = (int)get_local_id(0);

    for (int j = 0; j < BLOCK_SIZE; ++j) {
        shadow[tx * BLOCK_SIZE + j] =
            m[(offset + tx) * matrix_dim + (offset + j)];
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    for (int i = 0; i < BLOCK_SIZE - 1; ++i) {
        if (tx > i) {
            shadow[tx * BLOCK_SIZE + i] =
                shadow[tx * BLOCK_SIZE + i] / shadow[i * BLOCK_SIZE + i];
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        if (tx > i) {
            for (int j = i + 1; j < BLOCK_SIZE; ++j) {
                shadow[tx * BLOCK_SIZE + j] -=
                    shadow[tx * BLOCK_SIZE + i] * shadow[i * BLOCK_SIZE + j];
            }
        }

        barrier(CLK_LOCAL_MEM_FENCE);
    }

    for (int j = 0; j < BLOCK_SIZE; ++j) {
        m[(offset + tx) * matrix_dim + (offset + j)] =
            shadow[tx * BLOCK_SIZE + j];
    }
}

__kernel void lud_perimeter(__global float *m,
                            __local float *dia,
                            __local float *peri_row,
                            __local float *peri_col,
                            int matrix_dim,
                            int offset)
{
    const int tx = (int)get_local_id(0);
    const int bx = (int)get_group_id(0);

    if (tx < BLOCK_SIZE) {
        const int col = tx;
        const int j_global = offset + (bx + 1) * BLOCK_SIZE + col;

        for (int i = 0; i < BLOCK_SIZE; ++i) {
            dia[i * BLOCK_SIZE + col] =
                m[(offset + i) * matrix_dim + (offset + col)];
            peri_row[i * BLOCK_SIZE + col] =
                m[(offset + i) * matrix_dim + j_global];
        }
    } else {
        const int col = tx - BLOCK_SIZE;
        const int i_global = offset + (bx + 1) * BLOCK_SIZE;

        for (int i = 0; i < BLOCK_SIZE; ++i) {
            peri_col[i * BLOCK_SIZE + col] =
                m[(i_global + i) * matrix_dim + (offset + col)];
        }
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    if (tx < BLOCK_SIZE) {
        const int col = tx;
        const int j_global = offset + (bx + 1) * BLOCK_SIZE + col;

        for (int i = 0; i < BLOCK_SIZE; ++i) {
            float sum = 0.0f;
            for (int k = 0; k < i; ++k) {
                sum += dia[i * BLOCK_SIZE + k] *
                       peri_row[k * BLOCK_SIZE + col];
            }
            peri_row[i * BLOCK_SIZE + col] -= sum;
        }

        for (int i = 0; i < BLOCK_SIZE; ++i) {
            m[(offset + i) * matrix_dim + j_global] =
                peri_row[i * BLOCK_SIZE + col];
        }
    } else {
        const int row = tx - BLOCK_SIZE;
        const int i_global = offset + (bx + 1) * BLOCK_SIZE + row;

        for (int j = 0; j < BLOCK_SIZE; ++j) {
            float sum = 0.0f;
            for (int k = 0; k < j; ++k) {
                sum += peri_col[row * BLOCK_SIZE + k] *
                       dia[k * BLOCK_SIZE + j];
            }
            peri_col[row * BLOCK_SIZE + j] =
                (peri_col[row * BLOCK_SIZE + j] - sum) /
                dia[j * BLOCK_SIZE + j];
        }

        for (int j = 0; j < BLOCK_SIZE; ++j) {
            m[i_global * matrix_dim + (offset + j)] =
                peri_col[row * BLOCK_SIZE + j];
        }
    }
}

__kernel void lud_internal(__global float *m,
                           __local float *peri_row,
                           __local float *peri_col,
                           int matrix_dim,
                           int offset)
{
    const int tx = (int)get_local_id(0);
    const int ty = (int)get_local_id(1);
    const int bx = (int)get_group_id(0);
    const int by = (int)get_group_id(1);

    const int i_global = offset + (by + 1) * BLOCK_SIZE;
    const int j_global = offset + (bx + 1) * BLOCK_SIZE;

    peri_row[ty * BLOCK_SIZE + tx] =
        m[(offset + ty) * matrix_dim + (j_global + tx)];
    peri_col[ty * BLOCK_SIZE + tx] =
        m[(i_global + ty) * matrix_dim + (offset + tx)];

    barrier(CLK_LOCAL_MEM_FENCE);

    float sum = 0.0f;
    for (int k = 0; k < BLOCK_SIZE; ++k) {
        sum += peri_col[ty * BLOCK_SIZE + k] *
               peri_row[k * BLOCK_SIZE + tx];
    }

    m[(i_global + ty) * matrix_dim + (j_global + tx)] -= sum;
}
